You can copy this into a Rust project’s `main.rs` file, or use it in a library.

```rust
// Stack implementation in Rust

/// A stack data structure (Last-In, First-Out) with generic element type.
pub struct Stack<T> {
    items: Vec<T>,
}

impl<T> Stack<T> {
    /// Creates a new, empty Stack.
    pub fn new() -> Self {
        Stack { items: Vec::new() }
    }

    /// Pushes an item onto the stack.
    pub fn push(&mut self, item: T) {
        self.items.push(item);
    }

    /// Pops the top item off the stack. Returns `None` if the stack is empty.
    pub fn pop(&mut self) -> Option<T> {
        self.items.pop()
    }

    /// Peeks at the top item on the stack without removing it. Returns `None` if the stack is empty.
    pub fn peek(&self) -> Option<&T> {
        self.items.last()
    }

    /// Returns true if the stack is empty.
    pub fn is_empty(&self) -> bool {
        self.items.is_empty()
    }

    /// Returns the number of items in the stack.
    pub fn len(&self) -> usize {
        self.items.len()
    }
}

// Example usage:
fn main() {
    let mut stack = Stack::<i32>::new();

    // Push some values
    stack.push(1);
    stack.push(2);
    stack.push(3);

    println!("Stack length: {}", stack.len());

    // Peek at the top value
    if let Some(top) = stack.peek() {
        println!("Top value: {}", top);
    }

    // Pop values
    while let Some(value) = stack.pop() {
        println!("Popped: {}", value);
    }

    println!("Stack empty? {}", stack.is_empty());
}
```

**How it works:**
- The stack is implemented as a wrapper around `Vec<T>`, leveraging Rust's standard vector for efficiency.
- All common stack methods are provided.
- Example usage is shown in the `main` function.

