```rust
fn binary_search<T: Ord>(arr: &[T], target: &T) -> Option<usize> {
    let mut left = 0;
    let mut right = arr.len();

    while left < right {
        let mid = left + (right - left) / 2;
        match arr[mid].cmp(target) {
            std::cmp::Ordering::Equal => return Some(mid),
            std::cmp::Ordering::Less  => left = mid + 1,
            std::cmp::Ordering::Greater => right = mid,
        }
    }

    None
}

fn main() {
    let sorted = vec![1, 3, 5, 7, 9, 11];
    let target = 7;

    match binary_search(&sorted, &target) {
        Some(index) => println!("Found {} at index {}", target, index),
        None => println!("{} not found", target),
    }

    // Example: target not present
    let missing = 4;
    match binary_search(&sorted, &missing) {
        Some(index) => println!("Found {} at index {}", missing, index),
        None => println!("{} not found", missing),
    }
}
```

**How it works:**  
- Works for any type `T` that implements `Ord` (ordering).
- Searches `arr` for `target`.
- Returns `Some(index)` if found, or `None` if not.
- Demonstrated in `main()` with example searches.

